from azure.search.documents import SearchClient
from azure.core.credentials import AzureKeyCredential

def detect_metadata_leaks(search_service: SearchClient, query: str):
    results = search_service.search(
        search_text=query,
        select=['metadata_storage_path', 'content'],
        top=5
    )

    leaks = []
    for result in results:
        if 'sharepoint' in str(result.get('metadata_storage_path', '')).lower():
            leaks.append({
                'path': result['metadata_storage_path'],
                'has_content': bool(result.get('content'))
            })
    return leaks

def check_thread_token_usage(project_name: str, thread_id: str, client):
    thread = client.threads.get(project_name=project_name, thread_id=thread_id)

    total_tokens = sum(
        len(msg.content[0].text.value) for msg in thread.messages 
        if msg.content and msg.content[0].type == 'text'
    )

    max_tokens = 128000  # GPT-4 limit
    usage_pct = (total_tokens / max_tokens) * 100

    if usage_pct > 90:
        print(f'⚠️ Thread {thread_id} at {usage_pct:.1f}% token capacity')
        return {'critical': usage_pct > 95}
    return {'safe': True}

