from azure.ai.contentsafety import ContentSafetyClient
from azure.core.credentials import TokenCredential

def create_pii_redaction_middleware(credential: TokenCredential):
    safety_client = ContentSafetyClient(endpoint="https://your-cs-endpoint.cognitiveservices.azure.com/", credential=credential)

    def redact_agent_response(content: str) -> str:
        analyze_result = safety_client.analyze_text(
            text=content,
            categories=['PersonallyIdentifyingInformation']
        )

        if analyze_result.personally_identifying_information.detected:
            return '[REDACTED_PII]'
        return content

    return redact_agent_response

